// Shows pending orders with delivery fees
type Order record {|
    string id;
    string customer;
    int amount;
    string zone;
|};

public function main() {
    Order[] orders = [
        {id: "ORD001", customer: "Alice", amount: 150, zone: "Downtown"},
        {id: "ORD002", customer: "Bob", amount: 75, zone: "Suburb"},
        {id: "ORD003", customer: "Carol", amount: 200, zone: "Downtown"}
    ];
    map<int> deliveryFee = {"Downtown": 5, "Suburb": 10};

    io:println("=== Pending Orders ===");
    foreach int i in 0 ..< orders.length() {
        Order ord = orders[i];
        io:println(i + 1, ". ", ord.id, " | ",
                ord.customer, " | $", ord.amount,
                " | ", ord.zone, " (fee: $", deliveryFee[ord.zone], ")");
    }
}

import ballerina/io;

public function main() {
    int n = 10;
    int i = 0;
    while (i < n) {
        io:println("F(", i, ") = ", fibonacci(i));
        i += 1;
    }
}

function fibonacci(int n) returns int {
    if (n <= 1) {
        return n;
    }
    int prev = 0;
    int curr = 1;
    int i = 2;
    while (i <= n) {
        int next = prev + curr;
        prev = curr;
        curr = next;
        i += 1;
    }
    return curr;
}

import ballerina/io;

function validateFahrenheit(int f) returns int|error {
    if f < -459 {
        return error("invalid fahrenheit: below absolute zero");
    }
    return f;
}

function toCelsius(int f) returns int|error {
    int valid = check validateFahrenheit(f);
    return ((valid - 32) * 5) / 9;
}

function averageCelsius(int f1, int f2) returns int|error {
    int c1 = check toCelsius(f1);
    int c2 = check toCelsius(f2);
    return (c1 + c2) / 2;
}

function externalCalibrator(int c) returns int {
    // Simulate a dependency that may panic for suspicious values.
    if c > 100 {
        panic error("calibrator overflow");
    }
    return c + 1;
}

function safeConvertedValue(int f) returns int|error {
    int c = check toCelsius(f);
    var calibrated = trap externalCalibrator(c);
    if calibrated is error {
        return calibrated;
    }
    return calibrated;
}

function leaf(int f1, int f2) {
    _ = checkpanic averageCelsius(f1, f2);
}

function middle(int f1, int f2) {
    leaf(f1, f2);
}

function top(int f1, int f2) {
    middle(f1, f2);
}

public function main() {
    io:println("=== Temperature Converter ===");
    io:println("Safe Convert | Input: 98F");
    io:println("Result | ", safeConvertedValue(98));
    io:println("\nSafe Convert | Input: -500F");
    io:println("Result | ", safeConvertedValue(-500));
    io:println("\nAverage | Inputs: 98F, 32F");
    io:println("Result | ", averageCelsius(98, 32));
    io:println("\nStack Trace | top(-500, 32)");

    top(-500, 32);
}

import ballerina/io;

type Student record {|
    int id;
    string name;
    int grade;
|};

function findById(Student[] students, int studentId) returns Student|error {
    Student[] rows = from var s in students
        where s.id == studentId
        select s;

    if rows.length() == 0 {
        return error("student not found");
    }

    return rows[0];
}

function maxGrade(Student[] students) returns int {
    int best = students[0].grade;
    foreach Student s in students {
        if s.grade > best {
            best = s.grade;
        }
    }
    return best;
}

function averageGrade(Student[] students) returns int {
    int sum = 0;
    foreach Student s in students {
        sum += s.grade;
    }
    return sum / students.length();
}

function topStudents(Student[] students) returns Student[] {
    int best = maxGrade(students);
    Student[] rows = from var s in students
        where s.grade == best
        select s;
    return rows;
}

public function main() {
    Student[] students = [
        {id: 101, name: "Asha", grade: 78},
        {id: 102, name: "Nimal", grade: 92},
        {id: 103, name: "Ravi", grade: 85},
        {id: 104, name: "Sara", grade: 92}
    ];

    io:println("=== Student Grades ===");
    io:println("Average Grade | ", averageGrade(students));
    io:println("\nTop Students");
    Student[] tops = topStudents(students);
    foreach Student s in tops {
        io:println("- ", s.id, " | ", s.name, " | ", s.grade);
    }

    io:println("\nLookup | ID 102");
    var row1 = findById(students, 102);
    if row1 is Student {
        io:println("Found  | ", row1.id, " | ", row1.name, " | ", row1.grade);
    } else {
        io:println("Error  | ", row1);
    }

    io:println("\nLookup | ID 999");
    var row2 = findById(students, 999);
    if row2 is Student {
        io:println("Found  | ", row2.id, " | ", row2.name, " | ", row2.grade);
    } else {
        io:println("Error  | ", row2);
    }
}

import ballerina/io;

type LibraryItem object {
    function title() returns string;
    function author() returns string;
    function borrowMessage(boolean isBorrowed) returns string;
    function returnMessage(boolean isBorrowed) returns string;
};

class Book {
    *LibraryItem;
    string name;
    string writer;

    function init(string name, string writer) {
        self.name = name;
        self.writer = writer;
    }

    function title() returns string {
        return self.name;
    }

    function author() returns string {
        return self.writer;
    }

    function borrowMessage(boolean isBorrowed) returns string {
        if isBorrowed {
            return "Sorry, " + self.name + " is already borrowed.";
        }
        return "You borrowed " + self.name + ".";
    }

    function returnMessage(boolean isBorrowed) returns string {
        if !isBorrowed {
            return "This book was not borrowed.";
        }
        return "You returned " + self.name + ".";
    }
}

public function main() {
    LibraryItem book1 = new Book("The Hobbit", "J.R.R. Tolkien");
    LibraryItem book2 = new Book("Harry Potter and the Philosopher’s Stone", "J.K. Rowling");

    io:println("=== Library Checkout ===");
    io:println("Book 1 | ", book1.title(), " | ", book1.author());
    io:println("Book 2 | ", book2.title(), " | ", book2.author());

    boolean book1Borrowed = false;
    io:println("\nBorrow #1 | ", book1.borrowMessage(book1Borrowed));
    book1Borrowed = true;
    io:println("Borrow #2 | ", book1.borrowMessage(book1Borrowed));

    io:println("\nReturn #1 | ", book1.returnMessage(book1Borrowed));
    book1Borrowed = false;
    io:println("Return #2 | ", book1.returnMessage(book1Borrowed));
}
